```class Solution {
public:
    double new21Game(int n, int k, int maxPts) {
        if (k == 0) return 1.0;
        if (n >= k + maxPts) return 1.0;

        vector<double> dp(n + 1);
        for (int i = k; i <= min(n, k + maxPts - 1); ++i) {
            dp[i] = 1.0 / maxPts;
        }

        for (int i = k - 1; i >= 0; --i) {
            double sum = 0.0;
            for (int j = 1; j <= maxPts; ++j) {
                sum += dp[i + j];
            }
            dp[i] = sum / maxPts;
        }

        double res = 0.0;
        for (int i = 0; i <= n; ++i) {
            res += dp[i];
        }
        return res;
    }
};
